class RecentCounter {
private:
    vector<int> times;
public:
    RecentCounter() {}

    int ping(int t) {
        times.push_back(t);
        int lower = t - 3000;
        auto it = lower_bound(times.begin(), times.end(), lower);
        return times.end() - it;
    }
};

